export declare const actionBarTemplate = "\"use client\";\nimport { useContext, useState } from \"react\";\nimport styled, { css } from \"styled-components\";\nimport { Icon } from \"@/components/layout/Icon\";\nimport { mq, Theme } from \"@/app/theme\";\nimport { rgba } from \"polished\";\nimport { resetButton, Textarea } from \"cherry-styled-components/src/lib\";\nimport { ChatContext } from \"@/components/Chat\";\nimport links from \"@/links.json\";\n\ninterface ActionBarProps {\n  children: React.ReactNode;\n  content: string;\n}\n\nconst StyledActionBar = styled.div<{\n  theme: Theme;\n  $isChatOpen?: boolean;\n  $hasLinks?: boolean;\n}>`\n  position: absolute;\n  border-bottom: solid 1px ${({ theme }) => theme.colors.grayLight};\n  left: 0;\n  padding: 70px 20px 20px 20px;\n  display: flex;\n  justify-content: space-between;\n  width: 100%;\n  transition: all 0.3s ease;\n\n  ${({ $hasLinks }) =>\n    $hasLinks &&\n    css`\n      margin-top: 73px;\n    `}\n\n  ${mq(\"lg\")} {\n    left: 50%;\n    transform: translateX(-50%);\n    max-width: calc(100vw - 640px);\n    width: 100%;\n    padding: 0 20px 20px 20px;\n    margin: 0;\n\n    ${({ $hasLinks }) =>\n      $hasLinks &&\n      css`\n        margin-top: 73px;\n      `}\n\n    ${({ $isChatOpen }) =>\n      $isChatOpen &&\n      css`\n        padding: 0 120px 20px 20px;\n      `}\n  }\n`;\n\nconst StyledActionBarContent = styled.div`\n  margin: auto 0;\n`;\n\nconst StyledCopyButton = styled.button<{ theme: Theme; $copied: boolean }>`\n  background: transparent;\n  border: solid 1px\n    ${({ theme, $copied }) =>\n      $copied ? theme.colors.success : theme.colors.grayLight};\n  color: ${({ theme, $copied }) =>\n    $copied ? theme.colors.success : theme.colors.primary};\n  border-radius: ${({ theme }) => theme.spacing.radius.xs};\n  padding: 6px 8px;\n  font-size: 12px;\n  font-family: inherit;\n  font-weight: 600;\n  cursor: pointer;\n  transition: all 0.2s ease;\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  margin-right: -6px;\n\n  & svg.lucide {\n    color: ${({ theme, $copied }) =>\n      $copied ? theme.colors.success : theme.colors.primary};\n  }\n\n  &:hover {\n    border-color: ${({ theme, $copied }) =>\n      $copied ? theme.colors.success : theme.colors.primary};\n  }\n\n  &:active {\n    transform: scale(0.95);\n  }\n`;\n\nconst StyledToggle = styled.button<{ theme: Theme; $isActive?: boolean }>`\n  ${resetButton}\n  width: 56px;\n  height: 32px;\n  border-radius: 30px;\n  display: flex;\n  position: relative;\n  margin: auto 0;\n  transform: scale(1);\n  background: ${({ theme }) => theme.colors.light};\n  border: solid 1px ${({ theme }) => theme.colors.grayLight};\n\n  &::after {\n    content: \"\";\n    position: absolute;\n    top: 3px;\n    left: 3px;\n    width: 24px;\n    height: 24px;\n    border-radius: 50%;\n    background: ${({ theme }) => rgba(theme.colors.primaryLight, 0.2)};\n    transition: all 0.3s ease;\n    z-index: 1;\n    ${({ $isActive }) =>\n      !$isActive &&\n      css`\n        transform: translateX(24px);\n      `}\n  }\n\n  & svg {\n    width: 16px;\n    height: 16px;\n    object-fit: contain;\n    margin: auto;\n    transition: all 0.3s ease;\n    position: relative;\n    z-index: 2;\n  }\n\n  & .lucide-eye {\n    transform: translateX(1px);\n  }\n\n  & .lucide-code-xml {\n    transform: translateX(-1px);\n  }\n\n  & svg[stroke] {\n    stroke: ${({ theme }) => theme.colors.primary};\n  }\n\n  @media (hover: hover) {\n    &:hover {\n      transform: scale(1.05);\n      color: ${({ theme }) =>\n        theme.isDark ? theme.colors.primaryLight : theme.colors.primaryDark};\n      Toggle & svg[stroke] {\n        stroke: ${({ theme }) =>\n          theme.isDark ? theme.colors.primaryLight : theme.colors.primaryDark};\n      }\n    }\n  }\n\n  &:active {\n    transform: scale(0.97);\n  }\n`;\n\nconst StyledContent = styled.div<{\n  theme: Theme;\n  $isChatActive?: boolean;\n  $isChatOpen?: boolean;\n  $hasLinks?: boolean;\n}>`\n  padding-top: 140px;\n  transition: all 0.3s ease;\n\n  ${({ $hasLinks }) =>\n    $hasLinks &&\n    css`\n      padding-top: calc(73px + 140px);\n    `}\n\n  ${mq(\"lg\")} {\n    padding-top: 70px;\n    ${({ $isChatActive, $hasLinks }) =>\n      $isChatActive &&\n      $hasLinks &&\n      css`\n        padding-top: calc(73px + 140px);\n      `}\n\n    ${({ $isChatActive, $hasLinks }) =>\n      $isChatActive &&\n      !$hasLinks &&\n      css`\n        padding-top: 140px;\n      `}\n\n    ${({ $isChatOpen, $isChatActive, $hasLinks }) =>\n      $isChatOpen &&\n      $isChatActive &&\n      css`\n        padding-top: 70px;\n\n        ${$hasLinks &&\n        css`\n          padding-top: calc(73px + 70px);\n        `}\n      `}\n  }\n\n  & textarea {\n    max-width: 640px;\n    margin: auto;\n    width: 100%;\n    height: 100%;\n    min-height: calc(100vh - 180px);\n\n    ${({ $hasLinks }) =>\n      $hasLinks &&\n      css`\n        min-height: calc(100vh - 253px);\n      `}\n\n    ${({ $isChatOpen, $isChatActive, $hasLinks }) =>\n      !$isChatOpen &&\n      $isChatActive &&\n      css`\n        min-height: calc(100vh - 250px);\n\n        ${$hasLinks &&\n        css`\n          min-height: calc(100vh - 323px);\n        `}\n      `}\n\n    ${mq(\"lg\")} {\n      min-height: calc(100vh - 110px);\n\n      ${({ $hasLinks }) =>\n        $hasLinks &&\n        css`\n          min-height: calc(100vh - 183px);\n        `}\n\n      ${({ $isChatOpen, $isChatActive, $hasLinks }) =>\n        !$isChatOpen &&\n        $isChatActive &&\n        css`\n          min-height: calc(100vh - 180px);\n\n          ${$hasLinks &&\n          css`\n            min-height: calc(100vh - 253px);\n          `}\n        `}\n    }\n  }\n`;\n\nfunction ActionBar({ children, content }: ActionBarProps) {\n  const [isView, setIsView] = useState(true);\n  const [copied, setCopied] = useState(false);\n  const { isOpen, isChatActive } = useContext(ChatContext);\n\n  const handleCopyContent = async () => {\n    try {\n      await navigator.clipboard.writeText(content);\n      setCopied(true);\n      setTimeout(() => setCopied(false), 2000);\n    } catch (err) {\n      console.error(\"Failed to copy:\", err);\n    }\n  };\n\n  return (\n    <>\n      <StyledActionBar $isChatOpen={isOpen} $hasLinks={links.length > 0}>\n        <StyledCopyButton onClick={handleCopyContent} $copied={copied}>\n          {copied ? (\n            <>\n              <Icon name=\"check\" size={16} />\n              <span>Copied!</span>\n            </>\n          ) : (\n            <>\n              <Icon name=\"copy\" size={16} />\n              <span>Copy Content</span>\n            </>\n          )}\n        </StyledCopyButton>\n        <StyledActionBarContent>\n          {\" \"}\n          <StyledToggle\n            onClick={() => setIsView(!isView)}\n            aria-label=\"Toggle Theme\"\n            $isActive={isView}\n          >\n            <Icon name=\"Eye\" />\n            <Icon name=\"CodeXml\" />\n          </StyledToggle>\n        </StyledActionBarContent>\n      </StyledActionBar>\n      {isView && (\n        <StyledContent\n          $isChatActive={isChatActive}\n          $isChatOpen={isOpen}\n          $hasLinks={links.length > 0}\n        >\n          {children}\n        </StyledContent>\n      )}\n      {!isView && (\n        <StyledContent\n          $isChatActive={isChatActive}\n          $isChatOpen={isOpen}\n          $hasLinks={links.length > 0}\n        >\n          <Textarea defaultValue={content} $fullWidth />\n        </StyledContent>\n      )}\n    </>\n  );\n}\n\nexport { ActionBar };\n";
